#!/usr/bin/env python3
"""
Dependency Lock Management Script + Documentation (single-file)

Purpose
-------
Provide consistent dependency versions across development and production by
standardizing how we generate, update, and verify lock files.

Supports two workflows:
  1) pip-tools: requirements.in -> requirements.txt (with hashes)
  2) Poetry: pyproject.toml -> poetry.lock

This script can:
  - Detect which workflow is used in the repo
  - Generate/update lock files
  - Verify lock files are in sync and consistent
  - Print team-facing best practices and commands

Repository Conventions
----------------------
Option A (pip-tools):
  - requirements.in          (top-level direct deps; minimal pins)
  - requirements-dev.in      (dev-only deps; includes -r requirements.in)
  - requirements.txt         (compiled lock with hashes)
  - requirements-dev.txt     (compiled lock with hashes)

Option B (Poetry):
  - pyproject.toml           (direct deps + constraints)
  - poetry.lock              (resolved lock)

Best Practices Summary
----------------------
- Commit lock files to version control.
- Do not hand-edit generated lock files.
- Update dependencies intentionally:
    * Patch updates: update a single package
    * Minor/major updates: update selectively, review changelogs
- Use the lock file in CI and production builds.
- Verify lock consistency in CI (this script provides `verify`).

Usage
-----
  python tools/deps_lock.py help
  python tools/deps_lock.py detect
  python tools/deps_lock.py docs

pip-tools workflow:
  python tools/deps_lock.py pip-compile
  python tools/deps_lock.py pip-compile --upgrade
  python tools/deps_lock.py pip-compile --upgrade-package requests
  python tools/deps_lock.py pip-sync
  python tools/deps_lock.py verify

Poetry workflow:
  python tools/deps_lock.py poetry-lock
  python tools/deps_lock.py poetry-lock --update
  python tools/deps_lock.py poetry-install
  python tools/deps_lock.py verify

CI suggestion:
  - Run: python tools/deps_lock.py verify
  - For pip-tools: ensure requirements*.txt are up to date and include hashes
  - For Poetry: ensure poetry.lock is up to date with pyproject.toml

Notes
-----
- This script shells out to `pip-compile`, `pip-sync`, and `poetry`.
- Install tooling:
    pip install pip-tools
    pip install poetry  (or use official installer)
"""

from __future__ import annotations

import argparse
import os
import re
import shutil
import subprocess
import sys
from dataclasses import dataclass
from pathlib import Path
from typing import Iterable, Optional, Sequence


@dataclass(frozen=True)
class RepoLayout:
    root: Path
    has_poetry: bool
    has_pip_tools: bool
    pyproject: Path
    poetry_lock: Path
    req_in: Path
    req_txt: Path
    req_dev_in: Path
    req_dev_txt: Path


def run(cmd: Sequence[str], cwd: Optional[Path] = None, check: bool = True) -> subprocess.CompletedProcess:
    return subprocess.run(cmd, cwd=str(cwd) if cwd else None, check=check)


def capture(cmd: Sequence[str], cwd: Optional[Path] = None, check: bool = True) -> str:
    p = subprocess.run(cmd, cwd=str(cwd) if cwd else None, check=check, stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True)
    return p.stdout


def which(exe: str) -> Optional[str]:
    return shutil.which(exe)


def find_repo_root(start: Path) -> Path:
    cur = start.resolve()
    for _ in range(50):
        if (cur / ".git").exists() or (cur / "pyproject.toml").exists() or (cur / "requirements.in").exists():
            return cur
        if cur.parent == cur:
            return start.resolve()
        cur = cur.parent
    return start.resolve()


def detect_layout(root: Path) -> RepoLayout:
    pyproject = root / "pyproject.toml"
    poetry_lock = root / "poetry.lock"
    req_in = root / "requirements.in"
    req_txt = root / "requirements.txt"
    req_dev_in = root / "requirements-dev.in"
    req_dev_txt = root / "requirements-dev.txt"

    has_poetry = pyproject.exists()
    has_pip_tools = req_in.exists() or req_dev_in.exists() or req_txt.exists() or req_dev_txt.exists()

    return RepoLayout(
        root=root,
        has_poetry=has_poetry,
        has_pip_tools=has_pip_tools,
        pyproject=pyproject,
        poetry_lock=poetry_lock,
        req_in=req_in,
        req_txt=req_txt,
        req_dev_in=req_dev_in,
        req_dev_txt=req_dev_txt,
    )


def ensure_tool(exe: str, install_hint: str) -> None:
    if which(exe) is None:
        raise SystemExit(f"Missing required tool: {exe}\nInstall: {install_hint}")


def read_text(path: Path) -> str:
    return path.read_text(encoding="utf-8")


def file_contains_hashes(req_txt: Path) -> bool:
    if not req_txt.exists():
        return False
    txt = read_text(req_txt)
    return "--hash=" in txt


def pip_compile_files(layout: RepoLayout, upgrade: bool, upgrade_package: Optional[str], extra_args: Sequence[str]) -> None:
    ensure_tool("pip-compile", "pip install pip-tools")

    inputs_outputs = []
    if layout.req_in.exists():
        inputs_outputs.append((layout.req_in, layout.req_txt))
    if layout.req_dev_in.exists():
        inputs_outputs.append((layout.req_dev_in, layout.req_dev_txt))

    if not inputs_outputs:
        raise SystemExit("No requirements.in files found (expected requirements.in and/or requirements-dev.in).")

    base_cmd = ["pip-compile", "--generate-hashes"]
    if upgrade:
        base_cmd.append("--upgrade")
    if upgrade_package:
        base_cmd += ["--upgrade-package", upgrade_package]
    base_cmd += list(extra_args)

    for inp, outp in inputs_outputs:
        cmd = base_cmd + ["--output-file", str(outp), str(inp)]
        run(cmd, cwd=layout.root)


def pip_sync(layout: RepoLayout, dev: bool) -> None:
    ensure_tool("pip-sync", "pip install pip-tools")
    reqs = []
    if layout.req_txt.exists():
        reqs.append(str(layout.req_txt))
    if dev and layout.req_dev_txt.exists():
        reqs.append(str(layout.req_dev_txt))
    if not reqs:
        raise SystemExit("No compiled requirements.txt found. Run pip-compile first.")
    run(["pip-sync", *reqs], cwd=layout.root)


def poetry_lock(layout: RepoLayout, update: bool, extra_args: Sequence[str]) -> None:
    ensure_tool("poetry", "Install Poetry (https://python-poetry.org/docs/#installation)")
    if not layout.pyproject.exists():
        raise SystemExit("pyproject.toml not found; cannot use Poetry workflow.")
    cmd = ["poetry", "lock"]
    if update:
        cmd.append("--no-cache")
    cmd += list(extra_args)
    run(cmd, cwd=layout.root)


def poetry_install(layout: RepoLayout, with_dev: bool, extra_args: Sequence[str]) -> None:
    ensure_tool("poetry", "Install Poetry (https://python-poetry.org/docs/#installation)")
    cmd = ["poetry", "install"]
    if not with_dev:
        cmd += ["--only", "main"]
    cmd += list(extra_args)
    run(cmd, cwd=layout.root)


def verify_pip_tools(layout: RepoLayout) -> None:
    problems = []

    if layout.req_in.exists() and not layout.req_txt.exists():
        problems.append("requirements.in exists but requirements.txt is missing. Run: pip-compile")
    if layout.req_dev_in.exists() and not layout.req_dev_txt.exists():
        problems.append("requirements-dev.in exists but requirements-dev.txt is missing. Run: pip-compile")

    if layout.req_txt.exists() and not file_contains_hashes(layout.req_txt):
        problems.append("requirements.txt exists but does not include hashes. Rebuild with: pip-compile --generate-hashes")
    if layout.req_dev_txt.exists() and not file_contains_hashes(layout.req_dev_txt):
        problems.append("requirements-dev.txt exists but does not include hashes. Rebuild with: pip-compile --generate-hashes")

    ensure_tool("pip-compile", "pip install pip-tools")

    # Check compiled files are up-to-date by running pip-compile in dry-ish mode:
    # pip-compile has --quiet and --no-header, but no true --check.
    # We compare output to file content by compiling to stdout with -o - (not supported).
    # Instead, compile to a temp file and compare.
    import tempfile

    def compile_and_compare(inp: Path, outp: Path) -> Optional[str]:
        if not inp.exists() or not outp.exists():
            return None
        with tempfile.TemporaryDirectory() as td:
            tmp = Path(td) / outp.name
            cmd = ["pip-compile", "--generate-hashes", "--output-file", str(tmp), str(inp)]
            run(cmd, cwd=layout.root)
            a = read_text(outp).replace("\r\n", "\n")
            b = read_text(tmp).replace("\r\n", "\n")
            if a != b:
                return f"{outp.name} is not up to date with {inp.name}. Run: pip-compile"
        return None

    msg = compile_and_compare(layout.req_in, layout.req_txt)
    if msg:
        problems.append(msg)
    msg = compile_and_compare(layout.req_dev_in, layout.req_dev_txt)
    if msg:
        problems.append(msg)

    if problems:
        raise SystemExit("VERIFY FAILED:\n- " + "\n- ".join(problems))
    print("VERIFY OK (pip-tools): lock files present, hashed, and up to date.")


def verify_poetry(layout: RepoLayout) -> None:
    problems = []
    if not layout.pyproject.exists():
        problems.append("pyproject.toml missing.")
    if not layout.poetry_lock.exists():
        problems.append("poetry.lock missing. Run: poetry lock")

    ensure_tool("poetry", "Install Poetry (https://python-poetry.org/docs/#installation)")

    if layout.pyproject.exists() and layout.poetry_lock.exists():
        # Poetry provides a check command.
        out = capture(["poetry", "check"], cwd=layout.root, check=False)
        if "Error" in out or "errors" in out.lower():
            problems.append("poetry check reported issues:\n" + out.strip())

        # Ensure lock is in sync. `poetry lock --check` exists in newer versions.
        out2 = capture(["poetry", "lock", "--check"], cwd=layout.root, check=False)
        if "not consistent" in out2.lower() or "out of date" in out2.lower() or "needs to be regenerated" in out2.lower():
            problems.append("poetry.lock is not in sync with pyproject.toml. Run: poetry lock\n" + out2.strip())
        elif "error" in out2.lower() and "check" in out2.lower():
            # Older Poetry might not support --check; fall back to heuristic.
            pass

    if problems:
        raise SystemExit("VERIFY FAILED:\n- " + "\n- ".join(problems))
    print("VERIFY OK (Poetry): lock file present and consistent.")


DOCS_TEXT = """\
Dependency Management Best Practices (Team Standard)
===================================================

Goal
----
Ensure consistent dependency versions across development, CI, and production by:
- Defining direct dependencies in a source file (requirements.in or pyproject.toml)
- Generating a lock file (requirements.txt with hashes, or poetry.lock)
- Installing strictly from the lock file

Choose ONE workflow per repository
----------------------------------
A) pip-tools (requirements.in -> requirements.txt with hashes)
B) Poetry (pyproject.toml -> poetry.lock)

Do not mix lock workflows in the same project unless there is a clear, documented reason.

A) pip-tools Workflow
---------------------
Files:
- requirements.in: direct runtime deps (minimal pins; prefer ranges only when needed)
- requirements-dev.in: dev deps; should include runtime deps via:
    -r requirements.in
- requirements.txt: compiled lock with transitive deps + hashes
- requirements-dev.txt: compiled lock with transitive deps + hashes

Initial setup:
1) Create requirements.in (and requirements-dev.in if needed)
2) Install tooling:
   - python -m pip install pip-tools
3) Generate lock files:
   - pip-compile --generate-hashes -o requirements.txt requirements.in
   - pip-compile --generate-hashes -o requirements-dev.txt requirements-dev.in
4) Commit *.in and *.txt files.

Install (developer machine / CI):
- Runtime only:
    python -m pip install --require-hashes -r requirements.txt
- Dev:
    python -m pip install --require-hashes -r requirements-dev.txt

Sync environment exactly (recommended for CI and reproducible dev envs):
- pip-sync requirements.txt requirements-dev.txt

Updating dependencies:
- Update everything (use sparingly):
    pip-compile --generate-hashes --upgrade
- Update one package:
    pip-compile --generate-hashes --upgrade-package <name>
- After updating, run tests and commit updated requirements*.txt.

Production guidance:
- Build images / deploy using requirements.txt only (not requirements-dev.txt).
- Always use --require-hashes in production installs.

B) Poetry Workflow
------------------
Files:
- pyproject.toml: direct deps and constraints
- poetry.lock: resolved lock file

Initial setup:
1) Define dependencies:
   - poetry add <package>
   - poetry add --group dev <package>   (Poetry 1.2+)
2) Generate/update lock:
   - poetry lock
3) Install:
   - poetry install
   - poetry install --only main   (production-like)

Updating dependencies:
- Update all (use sparingly):
    poetry update
- Update one package:
    poetry update <name>
- Regenerate lock if needed:
    poetry lock

Production guidance:
- Prefer exporting a hashed requirements.txt for production pip installs if your runtime
  environment does not use Poetry:
    poetry export -f requirements.txt --output requirements.txt --without-hashes
  If you need hashes, use a plugin or a pip-tools based approach; otherwise ensure
  production uses Poetry directly.

CI checks (recommended)
-----------------------
- Ensure lock files are committed and up to date:
    python tools/deps_lock.py verify

Review and change control
-------------------------
- Treat lock file changes as code changes.
- Review diffs for unexpected additions/removals or major version bumps.
- Pin Python version (e.g., in pyproject.toml or a .python-version) and keep it consistent
  across dev/CI/prod to avoid resolver differences.

Common pitfalls
---------------
- Editing requirements.txt or poetry.lock by hand.
- Upgrading everything without review.
- Using unpinned transitive dependencies without a lock.
- Installing from requirements.in in production (not locked).
"""


def detect_workflow(layout: RepoLayout) -> str:
    poetry = layout.pyproject.exists() and layout.poetry_lock.exists()
    piptools = layout.req_in.exists() or layout.req_dev_in.exists() or layout.req_txt.exists() or layout.req_dev_txt.exists()

    if poetry and not piptools:
        return "poetry"
    if piptools and not poetry:
        return "pip-tools"
    if poetry and piptools:
        return "mixed"
    return "unknown"


def main(argv: Optional[Sequence[str]] = None) -> int:
    argv = list(argv or sys.argv[1:])
    parser = argparse.ArgumentParser(prog="deps_lock.py", add_help=False)
    sub = parser.add_subparsers(dest="cmd")

    sub.add_parser("help")
    sub.add_parser("docs")
    sub.add_parser("detect")
    sub.add_parser("verify")

    p_pc = sub.add_parser("pip-compile")
    p_pc.add_argument("--upgrade", action="store_true")
    p_pc.add_argument("--upgrade-package", default=None)
    p_pc.add_argument("extra", nargs=argparse.REMAINDER)

    p_ps = sub.add_parser("pip-sync")
    p_ps.add_argument("--dev", action="store_true", help="Include dev lock file if present")

    p_pl = sub.add_parser("poetry-lock")
    p_pl.add_argument("--update", action="store_true")
    p_pl.add_argument("extra", nargs=argparse.REMAINDER)

    p_pi = sub.add_parser("poetry-install")
    p_pi.add_argument("--with-dev", action="store_true", help="Install dev deps too")
    p_pi.add_argument("extra", nargs=argparse.REMAINDER)

    args = parser.parse_args(argv)
    if args.cmd in (None, "help"):
        print(__doc__.strip() + "\n")
        print("Commands: help, docs, detect, verify, pip-compile, pip-sync, poetry-lock, poetry-install")
        return 0

    root = find_repo_root(Path.cwd())
    layout = detect_layout(root)

    if args.cmd == "docs":
        print(DOCS_TEXT)
        return 0

    if args.cmd == "detect":
        wf = detect_workflow(layout)
        print(wf)
        return 0

    if args.cmd == "pip-compile":
        pip_compile_files(layout, upgrade=bool(args.upgrade), upgrade_package=args.upgrade_package, extra_args=args.extra)
        return 0

    if args.cmd == "pip-sync":
        pip_sync(layout, dev=bool(args.dev))
        return 0

    if args.cmd == "poetry-lock":
        poetry_lock(layout, update=bool(args.update), extra_args=args.extra)
        return 0

    if args.cmd == "poetry-install":
        poetry_install(layout, with_dev=bool(args.with_dev), extra_args=args.extra)
        return 0

    if args.cmd == "verify":
        wf = detect_workflow(layout)
        if wf == "pip-tools":
            verify_pip_tools(layout)
            return 0
        if wf == "poetry":
            verify_poetry(layout)
            return 0
        if wf == "mixed":
            # Verify both; fail if either fails.
            verify_pip_tools(layout)
            verify_poetry(layout)
            return 0
        raise SystemExit("Could not detect dependency workflow. Add requirements.in (pip-tools) or pyproject.toml+poetry.lock (Poetry).")

    raise SystemExit(f"Unknown command: {args.cmd}")


if __name__ == "__main__":
    raise SystemExit(main())